import React, { useEffect, useState } from "react";
import { getDebtDetails } from "../services/debtService";

export default function DebtDetails({ debtId }) {
  const [debt, setDebt] = useState(null);

  useEffect(() => {
    if (debtId) {
      loadDebtDetails();
    }
  }, [debtId]);

  async function loadDebtDetails() {
    try {
      const data = await getDebtDetails(debtId);

      setDebt(data);
    } catch (error) {
      console.error(error);
    }
  }

  if (!debtId) {
    return <p>Select a debt row to view details.</p>;
  }

  if (!debt) {
    return <p>Loading debt details...</p>;
  }

  return (
      <div className="container">
    <div style={{ marginTop: "20px" }}>

      <h2>Debt Details</h2>

      <table border="1" width="100%">
        <tbody>
          <tr>
            <td>Id</td>
            <td>{debt.id}</td>
          </tr>

          <tr>
            <td>Debt Reference</td>
            <td>{debt.debtReference}</td>
          </tr>

          <tr>
            <td>Original Balance</td>
            <td>{debt.originalBalance}</td>
          </tr>

          <tr>
            <td>Current Balance</td>
            <td>{debt.currentBalance}</td>
          </tr>

          <tr>
            <td>Creditor</td>
            <td>{debt.creditor}</td>
          </tr>

          <tr>
            <td>Debt Status Id</td>
            <td>{debt.debtStatusId}</td>
          </tr>

          <tr>
            <td>Debt Created Date</td>
            <td>{debt.debtCreatedDate}</td>
          </tr>
        </tbody>
      </table>
    </div>

    </div>
  );
}
